import * as React from 'react';

import AvatarGroup from '@mui/material/AvatarGroup';

import IconButton from '@mui/material/IconButton';

import { styled } from '@mui/material/styles';
import SearchRoundedIcon from '@mui/icons-material/SearchRounded';
import RssFeedRoundedIcon from '@mui/icons-material/RssFeedRounded';
import { OutlinedInput, InputAdornment } from '@mui/material';
import { Box, Chip, Card, CardMedia, CardContent, Typography, Avatar, Stack, Grid } from '@mui/material';

const cardData = [
  {
    category: 'WEB APPS',
    img: 'https://picsum.photos/800/450?random=1',
    tag: 'Engineering',
    title: 'Revolutionizing software development with cutting-edge tools',
    description:
      'Our latest engineering tools are designed to streamline workflows and boost productivity. Discover how these innovations are transforming the software development landscape.',
    authors: [
      { name: 'Remy Sharp', avatar: '/static/images/avatar/1.jpg' },
      { name: 'Travis Howard', avatar: '/static/images/avatar/2.jpg' },
    ],
  },
  {
    category: 'WEB APPS',
    img: 'https://picsum.photos/800/450?random=2',
    tag: 'Product',
    title: 'Innovative product features that drive success',
    description:
      'Explore the key features of our latest product release that are helping businesses achieve their goals. From user-friendly interfaces to robust functionality, learn why our product stands out.',
    authors: [{ name: 'Erica Johns', avatar: '/static/images/avatar/6.jpg' }],
  },
  {
    category: 'ANDROID APPS',
    img: 'https://picsum.photos/800/450?random=3',
    tag: 'Design',
    title: 'Designing for the future: trends and insights',
    description:
      'Stay ahead of the curve with the latest design trends and insights. Our design team shares their expertise on creating intuitive and visually stunning user experiences.',
    authors: [{ name: 'Kate Morrison', avatar: '/static/images/avatar/7.jpg' }],
  },
  {
    category: 'ANDROID APPS',
    img: 'https://picsum.photos/800/450?random=4',
    tag: 'Company',
    title: "Our company's journey: milestones and achievements",
    description:
      "Take a look at our company's journey and the milestones we've achieved along the way. From humble beginnings to industry leader, discover our story of growth and success.",
    authors: [{ name: 'Cindy Baker', avatar: '/static/images/avatar/3.jpg' }],
  },
  {
    category: 'MACHINE LEARNING MODELS',
    img: 'https://picsum.photos/800/450?random=45',
    tag: 'Engineering',
    title: 'Pioneering sustainable engineering solutions',
    description:
      "Learn about our commitment to sustainability and the innovative engineering solutions we're implementing to create a greener future. Discover the impact of our eco-friendly initiatives.",
    authors: [
      { name: 'Agnes Walker', avatar: '/static/images/avatar/4.jpg' },
      { name: 'Trevor Henderson', avatar: '/static/images/avatar/5.jpg' },
    ],
  },
  {
    category: 'MACHINE LEARNING MODELS',
    img: 'https://picsum.photos/800/450?random=6',
    tag: 'Product',
    title: 'Maximizing efficiency with our latest product updates',
    description:
      'Our recent product updates are designed to help you maximize efficiency and achieve more. Get a detailed overview of the new features and improvements that can elevate your workflow.',
    authors: [{ name: 'Travis Howard', avatar: '/static/images/avatar/2.jpg' }],
  },
  {
    category: 'GAMES',
    img: 'https://picsum.photos/800/450?random=7',
    tag: 'Entertainment',
    title: 'Revolutionizing gaming with immersive experiences',
    description:
      'Explore the future of gaming with our latest VR and AR-enabled games that provide players with an unforgettable immersive experience.',
    authors: [{ name: 'Sarah Lee', avatar: '/static/images/avatar/8.jpg' }],
  },
  {
    category: 'SELENIUM PROJECTS',
    img: 'https://picsum.photos/800/450?random=8',
    tag: 'Automation',
    title: 'Automating web testing with Selenium',
    description:
      'Our team has been using Selenium to automate web testing, saving time and ensuring high-quality performance across browsers and platforms.',
    authors: [{ name: 'James Smith', avatar: '/static/images/avatar/9.jpg' }],
  },
  {
    category: 'WEB3/BLOCKCHAIN APPS',
    img: 'https://picsum.photos/800/450?random=9',
    tag: 'Blockchain',
    title: 'Building decentralized applications for the future',
    description:
      'Explore the power of decentralized applications (dApps) and how they are transforming industries from finance to supply chain management.',
    authors: [{ name: 'Anna Walker', avatar: '/static/images/avatar/10.jpg' }],
  },
  {
    category: 'CHROME EXTENSIONS',
    img: 'https://picsum.photos/800/450?random=10',
    tag: 'Tools',
    title: 'Boosting productivity with our Chrome Extensions',
    description:
      'Our Chrome extensions are designed to help users stay productive by offering a variety of tools for improving workflow and task management.',
    authors: [{ name: 'David Brown', avatar: '/static/images/avatar/11.jpg' }],
  },
];

const SyledCard = styled(Card)(({ theme }) => ({
  display: 'flex',
  flexDirection: 'column',
  padding: 0,
  height: '100%',
  backgroundColor: (theme.vars || theme).palette.background.paper,
  '&:hover': {
    backgroundColor: 'transparent',
    cursor: 'pointer',
  },
  '&:focus-visible': {
    outline: '3px solid',
    outlineColor: 'hsla(210, 98%, 48%, 0.5)',
    outlineOffset: '2px',
  },
}));

const SyledCardContent = styled(CardContent)({
  display: 'flex',
  flexDirection: 'column',
  gap: 2,
  padding: 16,
  flexGrow: 1,
  '&:last-child': {
    paddingBottom: 16,
  },
});

const StyledTypography = styled(Typography)({
  display: '-webkit-box',
  WebkitBoxOrient: 'vertical',
  WebkitLineClamp: 2,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
});

function Author({ authors }) {
  return (
    <Box
      sx={{
        display: 'flex',
        flexDirection: 'row',
        gap: 2,
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '16px',
      }}
    >
      <Box
        sx={{ display: 'flex', flexDirection: 'row', gap: 1, alignItems: 'center' }}
      >
        <AvatarGroup max={3}>
          {authors.map((author, index) => (
            <Avatar
              key={index}
              alt={author.name}
              src={author.avatar}
              sx={{ width: 24, height: 24 }}
            />
          ))}
        </AvatarGroup>
        <Typography variant="caption">
          {authors.map((author) => author.name).join(', ')}
        </Typography>
      </Box>
      <Typography variant="caption">July 14, 2021</Typography>
    </Box>
  );
}

// export function Search() {
//   return (
//     <Box sx={{ width: { xs: '100%', md: '25ch' } }} variant="outlined">
//       <OutlinedInput
//         size="small"
//         id="search"
//         placeholder="Search…"
//         sx={{ flexGrow: 1 }}
//         startAdornment={
